from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
from flask_mail import Mail, Message
import os
import jwt
import datetime
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your_secret_key')
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD')

db = SQLAlchemy(app)
mail = Mail(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(128), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()
    if user:
        user.mfa_enabled = True
        db.session.commit()
        return jsonify({"message": "MFA enabled"}), 200
    return jsonify({"message": "User not found"}), 404

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()
    if user:
        user.mfa_enabled = False
        db.session.commit()
        return jsonify({"message": "MFA disabled"}), 200
    return jsonify({"message": "User not found"}), 404

@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.json.get('email')
    user = User.query.filter_by(email=email).first()
    if user:
        token = jwt.encode({'email': user.email, 'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=1)}, app.config['SECRET_KEY'])
        msg = Message('Reset MFA', sender='noreply@example.com', recipients=[user.email])
        msg.body = f'Click the link to reset MFA: http://localhost:5000/reset-mfa-link/{token}'
        mail.send(msg)
        return jsonify({"message": "Reset link sent"}), 200
    return jsonify({"message": "User not found"}), 404

@app.route('/reset-mfa-link/<token>', methods=['GET'])
def reset_mfa_link(token):
    try:
        data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=["HS256"])
        user = User.query.filter_by(email=data['email']).first()
        if user:
            user.mfa_enabled = False
            db.session.commit()
            return jsonify({"message": "MFA has been reset"}), 200
    except jwt.ExpiredSignatureError:
        return jsonify({"message": "Token has expired"}), 400
    except jwt.InvalidTokenError:
        return jsonify({"message": "Invalid token"}), 400
    return jsonify({"message": "User not found"}), 404

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)